// --- game.h (Header file) ---
#ifndef GAME_H
#define GAME_H

#include <string>
#include <vector>

// Constants
const int MAX_PLAYERS = 4;
const int MAX_LEVEL = 99;

// Structure declaration
struct Player {
    std::string name;
    int health;
    int attack;
    int defense;
    int level;
};

// Function declarations (prototypes)
void initializeGame();
void createPlayer(Player& player, const std::string& name);
void displayPlayer(const Player& player);
int calculateDamage(int attack, int defense);

#endif // GAME_H

// --- game.cpp (Implementation file) ---
#include "game.h"
#include <iostream>

void initializeGame() {
    std::cout << "=== Game Initialized ===" << std::endl;
    std::cout << "Max Players: " << MAX_PLAYERS << std::endl;
    std::cout << "Max Level: " << MAX_LEVEL << std::endl;
}

void createPlayer(Player& player, const std::string& name) {
    player.name = name;
    player.health = 100;
    player.attack = 15;
    player.defense = 10;
    player.level = 1;
    std::cout << "Player " << name << " created!" << std::endl;
}

void displayPlayer(const Player& player) {
    std::cout << "\n=== Player: " << player.name << " ===" << std::endl;
    std::cout << "Health: " << player.health << std::endl;
    std::cout << "Attack: " << player.attack << std::endl;
    std::cout << "Defense: " << player.defense << std::endl;
    std::cout << "Level: " << player.level << std::endl;
}

int calculateDamage(int attack, int defense) {
    int damage = attack - (defense / 2);
    return damage > 0 ? damage : 1;
}

// --- main.cpp (Main file) ---
#include "game.h"
#include <iostream>

int main() {
    initializeGame();

    Player hero;
    createPlayer(hero, "Hero");
    displayPlayer(hero);

    Player enemy;
    createPlayer(enemy, "Goblin");

    int damage = calculateDamage(hero.attack, enemy.defense);
    std::cout << "\nHero deals " << damage << " damage to Goblin!" << std::endl;

    return 0;
}

