// --- enemy.h (Header) ---
#ifndef ENEMY_H
#define ENEMY_H

#include <string>

struct Enemy {
    std::string name;
    int health;
    int attack;
};

void createEnemy(Enemy& enemy, const std::string& name, int health, int attack);
void displayEnemy(const Enemy& enemy);

#endif

// --- enemy.cpp (Implementation) ---
#include "enemy.h"
#include <iostream>

void createEnemy(Enemy& enemy, const std::string& name, int health, int attack) {
    enemy.name = name;
    enemy.health = health;
    enemy.attack = attack;
    std::cout << "Enemy " << name << " created!" << std::endl;
}

void displayEnemy(const Enemy& enemy) {
    std::cout << "Enemy: " << enemy.name 
              << " (HP: " << enemy.health 
              << ", ATK: " << enemy.attack << ")" << std::endl;
}

// --- main.cpp (Main) ---
#include "enemy.h"
#include <iostream>

int main() {
    std::cout << "=== Header Files Demo ===" << std::endl;

    Enemy goblin;
    createEnemy(goblin, "Goblin", 30, 8);
    displayEnemy(goblin);

    Enemy orc;
    createEnemy(orc, "Orc", 50, 12);
    displayEnemy(orc);

    return 0;
}
